mapper.select:
SELECT ID, USER_ID, PLATFORM, TOKEN, IS_ACTIVE, LAST_SEEN_AT, CREATED_AT, UPDATED_AT
FROM PUSH_TOKENS
WHERE TOKEN = #{token}

mapper.update:
UPDATE PUSH_TOKENS
SET USER_ID = #{userId},
    PLATFORM = #{platform},
    IS_ACTIVE = 1,
    LAST_SEEN_AT = #{lastSeenAt}
WHERE ID = #{id}

UPDATE PUSH_TOKENS
SET IS_ACTIVE = 0
WHERE USER_ID = #{userId}
  AND TOKEN = #{token}
  AND IS_ACTIVE = 1
